
<template>
    <va-affix :offset-top="35">
        <va-card color="white" gradient square outlined class="layout gutter--sm">
            <div class="row" style="padding:4px;">
                <va-button
                    block
                    class="m-2"
                    color="info"
                    style="padding:5px;"
                    :rounded="false"
                    @click="goBack"
                >返回檢測選取</va-button>
                <va-button
                    v-if="!gameEndChecker"
                    block
                    class="m-2"
                    color="success"
                    style="padding:5px;"
                    :rounded="false"
                    @click="SubmitRecordEndLocal"
                >
                    送出考卷（結束檢測）
                    <br />
                    {{ timeDisplay }}
                </va-button>
            </div>
        </va-card>
    </va-affix>
</template>

<script setup>
/* eslint-disable no-unused-vars */
import { inject, ref, onBeforeUnmount } from "vue";
import { useGameLogics } from "../compositions/useGameLogics";

const currentPage = inject("currentPage");

const { QuizsAnswerStatus, currentQUizs, SubmitRecordEnd, currentRecord, GetGames, GetPastGames, currentListFlag } = useGameLogics();

const gameEndChecker = ref(currentRecord.value.game_result.game_ended);

const SubmitRecordEndLocal = () => {
    SubmitRecordEnd();
    goBack();
}

const gameTimeLimit = new Date(currentRecord.value.game.time_limit).getTime();

const timeLeft = () => {
    if (gameEndChecker.value) return 0;
    return gameTimeLimit - new Date().getTime();
};

const timeDisplay = ref('');
const dayMSeconds = 24 * 60 * 60 * 1000;
const hourMSeconds = 60 * 60 * 1000;
const minuteMSeconds = 60 * 1000;

const timeCounter = setInterval(() => {
    const timeRaw = timeLeft();
    if (timeRaw > 0) {
        let days = Math.floor(timeRaw / dayMSeconds);
        let hours = Math.floor((timeRaw % dayMSeconds) / hourMSeconds);
        let minutes = Math.floor((timeRaw % hourMSeconds) / minuteMSeconds);
        let seconds = Math.floor((timeRaw % minuteMSeconds) / 1000);
        timeDisplay.value = `還有${days}天${hours}小時${minutes}分${seconds}秒`;
    } else {
        timeDisplay.value = '已結束';
    }
}, 1000);

onBeforeUnmount(() => {
    clearInterval(timeCounter);
});

const goBack = () => {
    currentQUizs.value.splice(0, currentQUizs.value.length);
    QuizsAnswerStatus.value.splice(0, QuizsAnswerStatus.value.length);
    currentListFlag.value === "Current" ? GetGames() : GetPastGames();
    currentPage.value = "GameList"
}


</script>

