
<template>
    <div class="row my-3">
        <va-card
            class="flex xs12 lg8 offset--lg2 align-content--center"
            style="
                padding: 1rem;
                "
        >
            <va-input v-if="listChecker" block v-model="searchGame" placeholder="搜尋檢測" />
            <table
                style="
                    width: 100%;
                    "
                class="va-table va-table--striped va-table--hoverable"
                v-if="listChecker"
                :key="refreshKey"
            >
                <thead>
                    <tr>
                        <th>檢測ID</th>
                        <th>檢測名稱</th>
                        <th>題目數量</th>
                        <th>答對題數</th>
                        <th>檢測期限</th>
                        <th>操作</th>
                    </tr>
                </thead>
                <tr v-for="(game,idx) in currentGames.filter(game=>game[1].participated)" :key="'game' + idx">
                    <td>{{ game[0] }}</td>
                    <td>{{ VBLevels.get(game[1].game_info.range) }}</td>
                    <td>{{ game[1].game_info.quiz_numbers }}</td>
                    <td>
                        {{
                            game[1].participated ?
                                game[1].record?.game_result.game_ended ? game[1].record.game_result.current_score : '檢測尚未完成' :
                                ''
                        }}
                    </td>
                    <td>{{ new Date(game[1].time_limit).toLocaleString("zh") }}</td>

                    <td>
                        <va-button
                            v-if="game[1].participated === false"
                            color="primary"
                            :disabled="!ConnectionChecker"
                            :loading="!ConnectionChecker"
                            @click="SubmitGame(game[0])"
                        >參加檢測</va-button>
                        <va-button
                            v-else-if="!game[1].record.game_result.game_ended"
                            color="success"
                            :disabled="!ConnectionChecker"
                            :loading="!ConnectionChecker"
                            @click="getQuizReal(game[0])"
                        >{{ game[1].record.game_result.ansed_quiz.length > 0 ? '繼續測驗' : '開始測驗' }}</va-button>
                        <va-button
                            v-else
                            color="dark"
                            :disabled="!ConnectionChecker"
                            :loading="!ConnectionChecker"
                            @click="getQuizReal(game[0])"
                        >檢視測驗結果</va-button>
                    </td>
                </tr>
            </table>
        </va-card>
    </div>
</template>

<script setup>
/* eslint-disable no-unused-vars */
import { inject, ref, watch } from "vue";
import { useGameLogics } from "../compositions/useGameLogics";
import BoyoVBLevels from "../const/BoyoVBLevel";
import { useWSConnection } from "../compositions/useWSConnection.js"
const { ConnectionChecker } = useWSConnection();

const currentPage = inject("currentPage");
const VBLevels = ref(new Map(
    BoyoVBLevels.map(level => [level.level, level.name])
));
const {
    SubmitGame,
    GetQuizs,
    gameLists,
    messageQueue
} = useGameLogics();

const listChecker = ref(false);
const refreshKey = ref(new Date().getTime() + 'GameList');
watch(() => [gameLists.value.length, messageQueue.size], (newVal) => {
    if (newVal[1] == 0) {
        currentGames.value = [...gameLists.value];
        listChecker.value = true;
        refreshKey.value = new Date().getTime() + 'GameList';
    }
})
const currentGames = ref([]);
const searchGame = ref("");
watch(() => [searchGame.value], (val) => {
    currentGames.value = [...gameLists.value];
    const [search] = val;
    if (search !== null && search.length > 0) {
        let searchArray = search.split(" ");
        searchArray.forEach(searchWord => {
            currentGames.value = currentGames.value.filter(game =>
                VBLevels.value.get(game[1].game_info.range).includes(searchWord) ||
                game[1].time_limit.toLocaleString('zh').includes(searchWord) ||
                game[0].toString().includes(searchWord)
            );
        })

    }
});

const getQuizReal = (record_id) => {
    GetQuizs(record_id);
    currentPage.value = "GamePlay";
}

</script>

