
<template>
    <div class="row">
        <va-card class="flex xs12 sm8 md6 lg4 offset--xs0 offset--sm2 offset--md3 offset--lg4" style="padding: 1em">
            <h3 class="text-center">系統更新日期：{{ version }}</h3>
            <va-form ref="form">
                <label for="username">帳號：</label>
                <va-input id="username" class="mb-4" v-model="username"
                    :rules="[value => (value && value.length > 0) || '必須有帳號名稱']" />
                <label for="password">密碼：</label>
                <va-input id="password" class="mb-4" v-model="password" type="password"
                    :rules="[value => (value && value.length > 0) || '必須輸入密碼']" />
                <va-button @click="LoginAccount">登入</va-button>
            </va-form>
        </va-card>
    </div>
</template>

<script setup>
/* eslint-disable no-unused-vars */
import { inject, ref } from "vue";
import { useLoading } from "../lib/vue-loading-screen/vuejs-loading-screen.esm"
import { useGameLogics } from "../compositions/useGameLogics";


const {
    Login,
} = useGameLogics();

const { VueLoading } = useLoading();

const form = ref(null);
const username = ref("");
const password = ref("");
const LoginAccount = async () => {
    VueLoading(true);
    await Login(username.value, password.value);
    VueLoading(false);
};
const version = process.env.VUE_APP_VERSION;

</script>

