import { useWSConnection } from "./useWSConnection";
import { ref, reactive } from "vue";
import axios from "axios";

export function useGameLogics() {
    return {
        GetPastGames,
        SubmitRecordEnd,
        GetGames,
        SubmitGame,
        GetRecords,
        SubmitAns,
        GetQuizs,
        Login,
        Logout,
        LogStatusCheck,
        updatePlayer,
        SubmitNewGame,
        currentListFlag,
        gameLists,
        examLists,
        currentRecord,
        currentQUizs,
        result,
        messageQueue,
        messageId,
        QuizsAnswerStatus,
        UserInfo,
    };
}
const currentListFlag = ref("Current")
const gameLists = ref([]);
const examLists = ref([]);
const currentQUizs = ref([]);
const currentRecord = ref(null)
const messageId = ref(1);
const messageQueue = reactive(new Set());
const result = ref(false);
const QuizsAnswerStatus = ref([]);
const UserInfo = reactive({
});
// 定時檢查messageQueue，避免系統卡住，每秒檢查一次
setInterval(() => {
    const nowTime = Date.now();
    if (messageQueue.size > 0) {
        for (const message of messageQueue) {
            const timeDifference = nowTime - message.time;
            if (timeDifference > 15000) {
                messageQueue.delete(message);
                console.log("指令逾時，已刪除，並重新發送一次");
                sendMessageQueue(message.message);
            }
        }
    }
}, 1000);

const {
    setToken,
    connectWS,
    setOnMessage,
    sendMessage,
    disconnectWS,
    setOnClose,
} = useWSConnection();

const getMyInfo = () => {
    sendMessageQueue({
        type: "GetMyInfo",
    });
}

const LogStatusCheck = async () => {
    let StoredToken = JSON.parse(localStorage.getItem('BoyoVBOnlinePlayer'));
    if (StoredToken === null) {
        return false;
    }
    try {
        setToken(StoredToken);
        setOnMessage(onmessage);
        setOnClose(resetSettings);
        await connectWS();
        getMyInfo();
        return true;
    } catch (err) {
        console.log(err);
        setToken(null);
        return false;
    }
}


const Logout = () => {
    setToken(null);
    disconnectWS();
    resetSettings();
    localStorage.removeItem('BoyoVBOnlinePlayer');
}



const Login = async (user_name, password) => {
    try {
        let url = "https://ams.boyo.org.tw/ws";
        let response = await axios.post(url + "/login", {
            user_name: user_name,
            password: password
        });
        let token = response.data.token;
        setToken(token);
        setOnMessage(onmessage);
        setOnClose(resetSettings);
        await connectWS();
        getMyInfo();
        localStorage.setItem('BoyoVBOnlinePlayer', JSON.stringify(token));
    } catch (err) {
        console.warn(err);
        window.alert("登入失敗！")
    }
}

const resetSettings = () => {
    Object.keys(UserInfo).forEach(key => {
        delete UserInfo[key];
    });
    currentListFlag.value = "Current";
    gameLists.value.splice(0, gameLists.value.length);
    examLists.value.splice(0, examLists.value.length);
    currentQUizs.value.splice(0, currentQUizs.value.length);
    currentRecord.value = null;
    messageId.value = 1;
    result.value = false;
    messageQueue.clear();
}

const updatePlayer = (player_info) => {
    sendMessageQueue({
        type: "UpdatePlayer",
        player_info: player_info,
    }
    );
};

function onmessage(data) {
    computeResult(data);
}
const computeResult = (data) => {
    if (data.type === undefined) {
        console.log("資料錯誤");
        return;
    }
    if (data.err_message.length > 0) {
        if (data.err_message.includes("檢測已經結束")) {
            window.alert("檢測已經結束，不可繼續作答喔！！");
        } else {
            window.alert(data.err_message);
        }
        if (data.id !== undefined) {
            for (let e of messageQueue.values()) {
                if (e.id == data.id) {
                    messageQueue.delete(e);
                    break;
                }
            }
        }
        return;
    }
    if (data.id !== undefined) {
        for (let e of messageQueue.values()) {
            if (e.id == data.id) {
                messageQueue.delete(e);
                break;
            }
        }
    }
    switch (data.type) {
        case "GetMyInfo": {
            let resultInfo = data.result.tag;
            if (resultInfo === undefined) {
                return;
            }
            Object.keys(resultInfo).forEach(key => {
                UserInfo[key] = resultInfo[key];
            });
            break;
        }
        case "SubmitGame":
            break;
        case "GetGames":
            currentListFlag.value = "Current";
            gameLists.value = [...data.result];
            gameLists.value.forEach(game => {
                game[1].participated = false;
            })
            // sort games by time limit
            gameLists.value.sort((a, b) => {
                return a[1].time_limit - b[1].time_limit;
            });
            break;
        case "GetPastGames":
            currentListFlag.value = "Past";
            gameLists.value = [...data.result.PlayedGames];
            gameLists.value.forEach(game => {
                game[1].participated = true;
            });
            examLists.value = [...data.result.PlayerGameRecords];
            gameLists.value.forEach(game => {
                let examChecker = examLists.value.find(record => {
                    return record.game_id == game[0];
                });
                if (examChecker !== undefined) {
                    game[1].participated = true;
                    game[1].record = examChecker;
                    examChecker.game = game[1];
                }
            });
            // sort games by time limit
            gameLists.value.sort((a, b) => {
                return b[1].time_limit - a[1].time_limit;
            });
            break;
        case "GetGameRecords":
            examLists.value = [...data.result];
            gameLists.value.forEach(game => {
                let examChecker = examLists.value.find(record => {
                    return record.game_id == game[0];
                });
                if (examChecker !== undefined) {
                    game[1].participated = true;
                    game[1].record = examChecker;
                    examChecker.game = game[1];
                }
            });
            break;
        case "GetQuizs": {
            currentQUizs.value = [...data.result];
            calculateAnsedStatus();
            break;
        } case "SubmitRecordAns":
            {
                let answeredQuizs = currentRecord.value.game_result.ansed_quiz;
                let result = data.result;
                let target = answeredQuizs.find(quiz => quiz.quiz_number == result.quiz_num);
                if (target === undefined) {
                    answeredQuizs.push({
                        quiz_number: result.quiz_num,
                        ans: result.ans,
                        checker: result.答題結果,
                    });
                } else {
                    target.ans = result.ans;
                    target.checker = result.答題結果;
                }
                calculateAnsedStatus();
                break;
            }
        case "UpdatePlayer": {
            getMyInfo();
            window.alert("更新成功！");
            break;
        }
        default:
            result.value = data;
            break;
    }
};

const SubmitRecordEnd = () => {
    const data = {
        "type": "SubmitRecordEnd",
        "record_id": currentRecord.value.record_id,
    };
    sendMessageQueue(data);
    currentQUizs.value.splice(0, currentQUizs.value.length);
    QuizsAnswerStatus.value.splice(0, QuizsAnswerStatus.value.length);
}

const sendMessageQueue = (message) => {
    message.id = messageId.value;
    const queueItem = {
        id: message.id,
        time: Date.now(),
        message: message,
    };
    try {
        messageQueue.add(queueItem);
        messageId.value += 1;
        sendMessage(message);
    } catch (err) {
        console.log(err);
        messageQueue.delete(queueItem);
    }
}

const GetGames = () => {
    const data = {
        "type": "GetGames",
    };
    sendMessageQueue(data);
    GetRecords();
};

const GetPastGames = () => {
    const data = {
        "type": "GetPastGames",
    };
    sendMessageQueue(data);
}

const SubmitGame = (game_id) => {
    const pass_word = window.prompt("請輸入密碼");
    if (pass_word == null || pass_word.length == 0) {
        return;
    }
    const data = {
        "type": "SubmitGame",
        "game_id": game_id,
        "password": pass_word,
    };
    sendMessageQueue(data);
    GetRecords();
};

const SubmitNewGame = (gameLevel) => {
    const data = {
        "type": "SubmitGameFreeVer",
        "gameLevel": parseInt(gameLevel)
    };
    sendMessageQueue(data);
    GetGames();
    GetRecords();
};

const GetRecords = () => {
    const data = {
        "type": "GetGameRecords",
    };
    sendMessageQueue(data);
};
const SubmitAns = (idx, ans) => {
    const data = {
        "type": "SubmitRecordAns",
        "record_id": currentRecord.value.record_id,
        "quiz_ans": ans,
        "quiz_num": idx
    };
    sendMessageQueue(data);
}

const GetQuizs = (game_id) => {
    let the_record = examLists.value.find(e => e.game_id === game_id);
    if (the_record === undefined) {
        window.alert("尚未參加此檢測？")
        return;
    }
    currentQUizs.value.splice(0, currentQUizs.value.length);
    currentRecord.value = the_record;
    const record_id = the_record.record_id;
    const data = {
        "type": "GetQuizs",
        "record_id": record_id,
    };
    sendMessageQueue(data);
}

const calculateAnsedStatus = () => {
    const answeredQuizs = currentRecord.value.game_result.ansed_quiz;
    const gameEndChecker = currentRecord.value.game_result.game_ended ||
        new Date(currentRecord.value.game.time_limit) < new Date();
    QuizsAnswerStatus.value = currentQUizs.value.map((item, idx) => {
        let answerStatus = answeredQuizs.find(e => e.quiz_number == idx);
        let status = {
            ans: answerStatus === undefined ? null : answerStatus.ans,
            checker: answerStatus === undefined ? null : answerStatus.checker,
            correct_ans: gameEndChecker ? item.answer : null,
        };
        return status;
    });
}
