import { Howl } from 'howler';
import howlsetting from "../assets/VB.json";
import {reactive,ref} from "vue";


const loaded = ref(false);
const loadPercent = ref(0);
const howl = reactive(new Howl({
    ...howlsetting,
    onprogress: function (e) {
        loadPercent.value = (e.loaded / e.total * 100).toFixed(2);
    }
}));
howl.once("load",()=>{
    loaded.value = true;
});

export function useHowl(){
    return {
        howl,
        loaded,
        loadPercent,
    }
}