<template>
  <NavBar />
  <SideBar />
  <div class="content">
    <router-view />
  </div>
</template>

<script>
import { defineComponent, onMounted, onBeforeMount, watch } from "vue";
import NavBar from "./components/NavBar.vue";
import SideBar from "./components/SideBar.vue";
import { useLoading } from "./lib/vue-loading-screen/vuejs-loading-screen.esm"
import { useGameLogics } from "./compositions/useGameLogics";
import { setColors } from 'vuestic-ui';

export default defineComponent({
  name: "App",
  setup() {
    const {
      messageQueue,
      LogStatusCheck
    } = useGameLogics();
    const { VueLoadingConfig, VueLoading } = useLoading();
    VueLoadingConfig({
      bg: "#90909090",
      slot: `
      <span class="material-icons bouncing1 loadingico">
      handyman
      </span>
      <span class="material-icons bouncing2 loadingico">
      military_tech
      </span>
      <span class="material-icons bouncing3 loadingico">
      fastfood
      </span>
      `});
    watch(() => [messageQueue.size], (values) => {
      if (values[0] > 0) {
        VueLoading(true);
      } else {
        VueLoading(false);
      }
    })
    onBeforeMount(async () => {
      setColors({
        primary: '#16d008',
      });
      await LogStatusCheck();
    });
    onMounted(async () => {
      let system_built_time = window.document.documentElement.dataset.buildTimestampUtc;
      let local_built_time = window.localStorage.getItem("BoyoVBCompetitionBuiltTime");
      if (local_built_time !== system_built_time) {
        window.localStorage.removeItem("BoyoVBCompetitionBuiltTime");
        window.localStorage.setItem("BoyoVBCompetitionBuiltTime", system_built_time);
      }
    });
  },
  components: { NavBar, SideBar }
});
</script>

<style>
.content {
  padding: 1rem;
}
</style>
