<template>
    <va-sidebar color="primary" :gradient="true" v-model="SideBarState" minimizedWidth="48px" width="12rem"
        style="position:fixed;">
        <va-sidebar-item>
            <va-sidebar-item-content>
                <va-sidebar-item-title :class="dWidth ? 'sidebarOff' : 'sidebarOff_small'">
                    <span>-</span>
                </va-sidebar-item-title>
            </va-sidebar-item-content>
        </va-sidebar-item>
        <va-sidebar-item v-if="ConnectionChecker">
            <va-sidebar-item-content>
                <va-icon name="co_present" />
                <va-sidebar-item-title @click="openURLNew('https://youtu.be/2K5q4hF_UCs')" style="height: 24px">使用教學
                </va-sidebar-item-title>
            </va-sidebar-item-content>
        </va-sidebar-item>
        <va-sidebar-item v-for="item in SideBarItems" :key="item.to"
            :active="router.currentRoute.value.name === item.to">
            <va-sidebar-item-content @click="go(item.to)" v-if="item.permission !== 'loggedin' || ConnectionChecker">
                <va-icon :name="item.icon" />
                <va-sidebar-item-title style="height: 24px">
                    {{
                    item.title
                    }}
                </va-sidebar-item-title>
            </va-sidebar-item-content>
        </va-sidebar-item>
    </va-sidebar>
</template>

<script setup>
import { useMenu } from "../compositions/useMenu";
import { router } from "../router";
import { DealingErrorRedirect } from "../lib/Utils";
import { computed } from "vue";
import WindowInstanceMap from "../lib/vuejs-usewiindohw";
import { useGameLogics } from "../compositions/useGameLogics";
import { useWSConnection } from "../compositions/useWSConnection";
const dWidth = computed(() =>
    WindowInstanceMap.innerWidth >= 480
);
const { Logout } = useGameLogics();
const { ConnectionChecker } = useWSConnection();

const { SideBarState, SideBarItems, toggleSideBar } = useMenu();
const go = (to) => {
    if (to === "logout") {
        toggleSideBar();
        Logout();
        router.push({
            name: "TestPlay"
        });
        return;
    }
    try {
        toggleSideBar();
        router.push({
            name: to
        });
        return;
    } catch (err) {
        DealingErrorRedirect(err);
    }
}

const openURLNew = (url) => {
    window.open(url, "_blank");
}


</script>

<style scoped>
.sidebarOff {
    align-items: stretch;
    text-align: center;
    color: white;
    font-size: 4rem;
}
.sidebarOff_small {
    align-items: stretch;
    text-align: center;
    color: white;
    font-size: 2rem;
}
</style>
